#include <vector>
using namespace std;
class Solution {
public:
bool isValidSudoku(vector<vector<int>>& board) {
    for (int i = 0; i < 9; ++i) {
        for (int j = 0; j < 9; ++j) {
            if (board[i][j] == 0) continue;
            if (board[i][j] < 1 || board[i][j] > 9) return false;
            int count = 0;
            for (int k = 0; k < 9; ++k) {
                if (board[i][k] == board[i][j]) ++count;
            }
            if (count != 1) return false;
        }
    }
    return true;
}
};
